SELECT stock_name, last_updated
FROM stocks
ORDER BY last_updated DESC;

SELECT SUM(market_cap) 
FROM sectors 
WHERE sector_name = 'Finance';

SELECT COUNT(trading_hour_id) AS num_trading_hours
FROM trading_hours
WHERE exchange_id = 0;

SELECT SUM(volume) AS total_volume
FROM trading_volumes
WHERE stock_id = 1 AND datetime = '2022-05-02 23:00:00';

SELECT industry_name
FROM industries
WHERE industry_name = 'Software';

SELECT SUM(CAST(REPLACE(REPLACE(market_cap, '$', ''), ',', '') AS REAL)) AS total_market_cap
FROM stocks
WHERE sector = 'Technology';
